"use client";

import Link from "next/link";
import { Logo } from "@/components/logo";
import { Menu, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import React from "react";
import { cn } from "@/lib/utils";

const navItems = ["Home", "Features", "Integration", "Pricing"];

export default function Navbar() {
  const [menuOpen, setMenuOpen] = React.useState(false);

  return (
    <nav className="relative z-10 max-w-7xl mx-auto px-3 sm:px-4 md:px-6 lg:px-8 pt-4 sm:pt-6 md:pt-8">
      <div className="bg-background/80 backdrop-blur-xl rounded-2xl sm:rounded-3xl px-4 sm:px-5 py-3 sm:py-4 flex items-center justify-between border border-border/50 shadow-lg shadow-primary/5">
        <Link href="/" aria-label="home">
          <Logo />
        </Link>

        {/* Desktop Navigation */}
        <div className="hidden md:flex items-center gap-6 lg:gap-8">
          {navItems.map((item) => (
            <Link
              key={item}
              href="#"
              className="text-muted-foreground hover:text-foreground transition-colors text-sm"
            >
              {item}
            </Link>
          ))}
        </div>

        {/* Desktop CTA */}
        <div className="hidden md:block">
          <Button asChild size="sm" className="rounded-full px-5">
            <Link href="#">
              <span>Get started</span>
            </Link>
          </Button>
        </div>

        {/* Mobile Menu Button */}
        <button
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label={menuOpen ? "Close Menu" : "Open Menu"}
          className="relative z-20 -m-2 p-2 md:hidden"
        >
          <Menu
            className={cn(
              "size-6 transition-all duration-200",
              menuOpen && "hidden"
            )}
          />
          <X
            className={cn(
              "size-6 transition-all duration-200",
              !menuOpen && "hidden"
            )}
          />
        </button>
      </div>

      {/* Mobile Menu */}
      {menuOpen && (
        <div className="md:hidden mt-3 bg-background rounded-2xl border border-border p-4 shadow-xl shadow-primary/5">
          <ul className="space-y-3">
            {navItems.map((item) => (
              <li key={item}>
                <Link
                  href="#"
                  className="block text-muted-foreground hover:text-foreground transition-colors py-2"
                  onClick={() => setMenuOpen(false)}
                >
                  {item}
                </Link>
              </li>
            ))}
          </ul>
          <div className="mt-4 pt-4 border-t border-border">
            <Button asChild className="w-full rounded-full">
              <Link href="#">
                <span>Get started</span>
              </Link>
            </Button>
          </div>
        </div>
      )}
    </nav>
  );
}
